// Monta UMA mensagem única com todos os experimentos rodando.
const items = $input.all();
const planilhaUrl = 'https://docs.google.com/spreadsheets/d/1v8dDnjwihOFBGwcDhYSTV0rnorlUxXPnT5JGPUrjk64/edit?gid=168394971';
const hoje = $now.toFormat('dd/MM/yyyy');

// Mapa: Responsável (como aparece na planilha) -> Slack member ID (U...).
// Pegue o ID no Slack: perfil da pessoa -> ⋯ (More) -> Copy member ID.
const SLACK_IDS = {
  'alexandre': 'U05NBR6D2MV',     // alexandre.magno
  'gabriel': 'U0A3Q0YQD97',       // gabriel.santos
  'joao paulo': 'U08B2PT8W95',    // joao.paulo
  'antonio carlos': 'U06AG7DQLHW', // antonio.carlos
};

// normaliza: minúsculo, sem acento, sem espaços nas pontas
const norm = (s) => (s || '').toString().trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const mencao = (resp) => {
  const id = SLACK_IDS[norm(resp)];
  return (id && !id.startsWith('U_TROCAR')) ? `<@${id}>` : (resp || '—');
};

const linhas = [];
for (const it of items) {
  const j = it.json;
  const id = (j['ID'] || '').toString().trim();
  const nome = (j['Nome curto'] || '').toString().trim();
  const resp = (j['Responsável'] || '—').toString().trim();
  const metrica = (j['Métrica'] || '—').toString().trim();
  const termino = (j['Data término'] || '').toString().trim();
  const jira = (j['Link Jira'] || '').toString().trim();

  const prazo = termino ? ` · 🏁 termina ${termino}` : '';
  const jiraTxt = jira ? ` · <${jira}|Jira>` : '';
  const titulo = id ? `*${id}* — ${nome}` : `*${nome}*`;
  linhas.push(`• ${titulo}\n     👤 ${mencao(resp)} · 📈 ${metrica}${prazo}${jiraTxt}`);
}

let texto;
if (linhas.length === 0) {
  texto = `📊 *Experimentos ativos* — ${hoje}\n\nNenhum experimento com status *Rodando* hoje. 🎉`;
} else {
  texto = `📊 *Experimentos rodando hoje* — ${hoje} (${linhas.length})\n\nLembrem de preencher a métrica do dia na planilha 👇\n\n${linhas.join('\n\n\n')}\n\n🔗 <${planilhaUrl}|Abrir planilha de experimentos>`;
}

return [{ json: { texto, total: linhas.length } }];
